// ═══════════════════════════════════════════════════
// FLOWER SVG RENDERER
// ═══════════════════════════════════════════════════
// Each flower function receives (petal, center, dark) hex colors
// and returns a complete SVG string in its original viewBox.

function flowerSVG(flowerKey, petalHex, size) {
  size = size || 100;
  const center = lighten(petalHex, 40);
  const dark   = darken(petalHex, 30);

  const fns = {
    '蔷薇':   svgRose,
    '向日葵': svgSunflower,
    '非洲菊': svgGerbera,
    '紫菀': svgAster,
    '水仙':   svgDaffodil,
    '星芹':   svgAstrantia,
    '铁线莲': svgClematis,
    '矢车菊':   svgKornblume,
	'木兰':   svgMagnolia,
	'含羞草':   svgMimosa,
	'罂粟':   svgPoppy,
    '康乃馨': svgCarnation,
  };
  const fn = fns[flowerKey] || svgRose;
  const svgStr = fn(petalHex, center, dark);
  // Wrap in sized container
  return svgStr.replace(/width="[^"]*"/, `width="${size}"`).replace(/height="[^"]*"/, `height="${size}"`);
}

// ── COLOR HELPERS ──────────────────────────────────────
function hexToRgb(hex) {
  const r = parseInt(hex.slice(1,3),16), g = parseInt(hex.slice(3,5),16), b = parseInt(hex.slice(5,7),16);
  return [r,g,b];
}
function rgbToHex(r,g,b) {
  return '#'+[r,g,b].map(v=>Math.min(255,Math.max(0,Math.round(v))).toString(16).padStart(2,'0')).join('');
}
function lighten(hex, amt) {
  const [r,g,b] = hexToRgb(hex);
  return rgbToHex(r+amt, g+amt, b+amt);
}
function darken(hex, amt) {
  const [r,g,b] = hexToRgb(hex);
  return rgbToHex(r-amt, g-amt, b-amt);
}


